create table product_attribute_values
(
    product_id   uniqueidentifier                                not null
        constraint FK_product_attribute_values_products_product_id
            references products
            on delete cascade,
    attribute_id int                                             not null
        constraint FK_product_attribute_values_product_attributes_attribute_id
            references product_attributes
            on delete cascade,
    Value        nvarchar(2000),
    created_at   datetime2 default '0001-01-01T00:00:00.0000000' not null,
    deleted_at   datetime2,
    modified_at  datetime2,
    constraint PK_product_attribute_values
        primary key (product_id, attribute_id)
)
go

create index IX_product_attribute_values_attribute_id
    on product_attribute_values (attribute_id)
go

