INSERT INTO yumilk.dbo.product_attribute_values (product_id, attribute_id, value, created_at, deleted_at, modified_at) VALUES (N'89BB7676-C6BE-49C8-B6C2-1FA0D6691515', 7, N'Singapore', N'2024-06-29 09:51:30.0000000', null, null);
INSERT INTO yumilk.dbo.product_attribute_values (product_id, attribute_id, value, created_at, deleted_at, modified_at) VALUES (N'A83DDEEB-E49C-4A5A-A7A1-29E5B1F87FFC', 1, N'. Rửa tay và dụng cụ pha thật kỹ bằng nước sạch. . Đun sôi các dụng cụ pha trong vòng ít nhất 3 phút. . Đun sôi nước trong vòng 5 phút, sau đó để nguội dần đến 40°C (nước ấm) trước khi pha để đảm bảo các vi khuẩn có ích còn sống. . Cho 7 muỗng gạt vào 180ml nước đun sôi để ấm khoảng 40oC và khuấy đều (1 muỗng gạt ngang tương đương 6.4g sản phẩm). . Sử dụng phần sản phẩm đã pha trong vòng 1 giờ sau khi pha. Đổ bỏ phần uống còn dư.', N'2024-07-11 01:32:55.7453437', null, null);
INSERT INTO yumilk.dbo.product_attribute_values (product_id, attribute_id, value, created_at, deleted_at, modified_at) VALUES (N'A83DDEEB-E49C-4A5A-A7A1-29E5B1F87FFC', 2, N'. Bảo quản nơi khô ráo, sạch sẽ, thoáng mát, tránh ánh nắng trực tiếp. . Đậy kín nắp hộp sau khi mở và để ở nơi mát, khô ráo. . Không nên cho sản phẩm vào tủ lạnh. . Nên sử dụng trong vòng 4 tuần từ khi mở sản phẩm.', N'2024-07-11 01:33:03.9274977', null, null);
